import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faUser as faUserSolid } from '@fortawesome/free-regular-svg-icons';
import CouponCard from '../components/CouponCard';

interface UserPageProps {
  setIsChatOpen: (open: boolean) => void;
}

const TABS = [
  { key: 'orders', label: '주문내역' },
  { key: 'payments', label: '결제내역' },
  { key: 'favorits', label: '즐겨찾기한 서비스' },
  { key: 'coupons', label: '쿠폰함' },
  { key: 'settings', label: '환경설정' },
];

const COUPON_TABS = [
  { key: 'available', label: '사용 가능' },
  { key: 'used', label: '사용 완료' },
  { key: 'all', label: '전체 쿠폰' },
];

const DUMMY_COUPONS = [
  {
    id: 1,
    name: '가입 환영 10% 할인 쿠폰',
    expire: '2025년 07월 09일 13:49 까지',
    desc: '(최대 10,000원 할인)',
    status: '사용 가능',
    percent: 10,
    type: 'available',
  },
  {
    id: 2,
    name: '가입 환영 10% 할인 쿠폰',
    expire: '2025년 07월 09일 13:49 까지',
    desc: '(최대 10,000원 할인)',
    status: '사용 가능',
    percent: 10,
    type: 'available',
  },
  {
    id: 3,
    name: '가입 환영 10% 할인 쿠폰',
    expire: '2025년 07월 09일 13:49 까지',
    desc: '(최대 10,000원 할인)',
    status: '사용 가능',
    percent: 10,
    type: 'available',
  },
];

const UserPage: React.FC<UserPageProps> = ({ setIsChatOpen }) => {
  const [activeTab, setActiveTab] = useState('mypage');
  const [couponTab, setCouponTab] = useState('all');
  const navigate = useNavigate();
  const handleLogout = () => {
    localStorage.removeItem('isLoggedIn');
    localStorage.removeItem('userEmail');
    navigate('/');
  };
  return (
    <div className="bg-gray-50 py-8 pb-20">
      <div className="max-w-5xl mx-auto flex gap-8">
        {/* Sidebar */}
        <aside className="w-64">
          <div className="bg-white rounded-lg shadow p-4 mb-6">
            <div className="font-bold text-sm mb-2">내 주문 현황</div>
            <div className="flex justify-between text-xs mb-1">
              <span className="text-gray-500">진행 중</span>
              <span className="font-semibold">0 건</span>
            </div>
            <div className="flex justify-between text-xs mb-1">
              <span className="text-gray-500">완료</span>
              <span className="font-semibold">0 건</span>
            </div>
            <div className="flex justify-between text-xs mb-1">
              <span className="text-gray-500">쿠폰</span>
              <span className="font-semibold text-blue-600">3 개</span>
            </div>
            <div className="flex justify-between text-xs">
              <span className="text-gray-500">포인트</span>
              <span className="font-semibold text-blue-600">0 P</span>
            </div>
          </div>
          <nav className="text-sm mb-6 pb-20">
            <button onClick={() => setActiveTab('mypage')} 
                className={`block w-full text-left px-2 py-2 rounded font-bold mb-1 
                ${activeTab === 'mypage' ? 'bg-orange-50 text-orange-600' : 'text-orange-700 hover:bg-gray-100'}`}>마이페이지</button>
            <button onClick={() => setIsChatOpen(true)} 
                className="block w-full text-left px-2 py-2 rounded hover:bg-gray-100">1:1 상담</button>
            {TABS.map(tab => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key)}
                className={`block w-full text-left px-2 py-2 rounded transition font-semibold mb-1 ${
                  activeTab === tab.key
                    ? 'bg-orange-50 text-orange-600 font-bold' : 'text-gray-700 hover:bg-gray-100'
                }`}
              >
                {tab.label}
              </button>
            ))}
            <div className="border-t border-gray-200 pt-2">
              <button onClick={handleLogout} 
                  className="block w-full text-left px-2 py-2 rounded hover:bg-gray-100 font-semibold text-red-500">로그아웃</button>
            </div>
          </nav>
        </aside>
        {/* Main Content */}
        <section className="flex-1 border border-red-500">
          {/* 마이페이지 대시보드(새소식, 주문현황 등): 마이페이지 탭일 때만 보임 */}
          {activeTab === 'mypage' && (
            <div className="bg-white rounded-lg shadow p-6 mb-6 min-h-[100px] border border-red-500">
              <div className="font-bold text-gray-700 mb-2">애드모어 새소식</div>
              <div className="bg-gray-100 rounded p-3 text-xs text-gray-600 mb-4">애드모어 런칭 <span className="text-orange-500 font-bold ml-2">2023-02-22</span></div>
              <div className="bg-teal-400 w-full h-40 rounded-lg p-8 text-center text-white font-bold text-2xl mb-12 flex items-center justify-center">
                지금 애드모어를 이용하시면, 최대 10프로 할인
              </div>
              <div className="flex justify-between items-center mb-4">
                <span className="text-sm text-gray-600 font-semibold">주문 현황</span>
                <Link to="#" className="text-xs text-blue-600">자세히보기 &gt;</Link>
              </div>
              <div className="flex justify-between items-center mb-4">
                <div className="flex flex-col items-center flex-1">
                  <span className="text-orange-400 text-2xl mb-1">📋</span>
                  <span className="text-xs">가상 계좌 발급</span>
                  <span className="text-xs font-bold">0건</span>
                </div>
                <div className="flex flex-col items-center flex-1">
                  <span className="text-purple-500 text-2xl mb-1">💳</span>
                  <span className="text-xs">결제 완료</span>
                  <span className="text-xs font-bold">0건</span>
                </div>
                <div className="flex flex-col items-center flex-1">
                  <span className="text-blue-500 text-2xl mb-1">⏳</span>
                  <span className="text-xs">진행 중</span>
                  <span className="text-xs font-bold">0건</span>
                </div>
                <div className="flex flex-col items-center flex-1">
                  <span className="text-green-500 text-2xl mb-1">✅</span>
                  <span className="text-xs">완료</span>
                  <span className="text-xs font-bold">0건</span>
                </div>
                <div className="flex flex-col items-center flex-1">
                  <span className="text-red-400 text-2xl mb-1">⛔</span>
                  <span className="text-xs">취소</span>
                  <span className="text-xs font-bold">0건</span>
                </div>
              </div>
            </div>
          )}
          {/* 탭별 컨텐츠: 마이페이지가 아닐 때만 보여줌 */}
          {activeTab !== 'mypage' && (
            <div className="bg-white rounded-lg shadow p-6 min-h-[50vh]">
              {activeTab === 'coupons' && (
                <div>
                  {/* 상단 요약/입력 영역 */}
                  <div className="bg-white rounded-lg border p-6 mb-6">
                    <div className="flex items-center justify-between mb-4">
                      <div className="flex items-center gap-4">
                        <span className="font-semibold text-lg">사용 가능한 쿠폰</span>
                        <span className="text-2xl font-bold text-orange-600">3</span>
                        <span className="text-gray-400">개</span>
                      </div>
                      <div className="flex items-center gap-4">
                        <span className="font-semibold text-lg">전체 쿠폰</span>
                        <span className="text-2xl font-bold text-orange-600">3</span>
                        <span className="text-gray-400">개</span>
                      </div>
                    </div>
                    <div className="flex gap-2 mb-2">
                      <input type="text" className="flex-1 border rounded px-3 py-2 text-sm" placeholder="보유하신 쿠폰 코드를 입력해 주세요." />
                      <button className="bg-orange-500 text-white px-6 py-2 rounded font-semibold hover:bg-orange-600">등록</button>
                    </div>
                  </div>
                  {/* 쿠폰 필터 탭 */}
                  <div className="flex border-b mb-6">
                    {COUPON_TABS.map(tab => (
                      <button
                        key={tab.key}
                        className={`px-6 py-2 font-semibold text-sm border-b-2 transition-all -mb-px ${
                          couponTab === tab.key ? 'border-orange-600 text-orange-600' : 'border-transparent text-gray-400 hover:text-orange-600'
                        }`}
                        onClick={() => setCouponTab(tab.key)}
                      >
                        {tab.label}
                      </button>
                    ))}
                  </div>
                  {/* 쿠폰 카드 리스트 */}
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {DUMMY_COUPONS.filter(c => couponTab === 'all' || c.type === couponTab).length === 0 ? (
                      <div className="col-span-3 text-center text-gray-400 py-12">쿠폰이 없습니다.</div>
                    ) : (
                      DUMMY_COUPONS.filter(c => couponTab === 'all' || c.type === couponTab).map(coupon => (
                        <CouponCard
                          key={coupon.id}
                          title={coupon.name}
                          expiry={coupon.expire}
                          maxDiscount={10000}
                          discountRate={coupon.percent}
                          onUse={() => alert(`${coupon.name} 사용!`)}
                        />
                      ))
                    )}
                  </div>
                </div>
              )}
              {activeTab === 'orders' && (
                <div>
                  <div className="font-bold mb-2">주문내역</div>
                  <table className="w-full text-sm border">
                    <thead>
                      <tr className="bg-gray-50">
                        <th className="p-2 border">주문번호</th>
                        <th className="p-2 border">상품명</th>
                        <th className="p-2 border">상태</th>
                        <th className="p-2 border">날짜</th>
                      </tr>
                    </thead>
                    <tbody>
                      <tr>
                        <td className="p-2 border">20240601-001</td>
                        <td className="p-2 border">유튜브 구독자 100명</td>
                        <td className="p-2 border">완료</td>
                        <td className="p-2 border">2024-06-01</td>
                      </tr>
                    </tbody>
                  </table>
                </div>
              )}
              {activeTab === 'payments' && (
                <div>
                  <div className="font-bold mb-2">결제내역</div>
                  <table className="w-full text-sm border">
                    <thead>
                      <tr className="bg-gray-50">
                        <th className="p-2 border">결제번호</th>
                        <th className="p-2 border">금액</th>
                        <th className="p-2 border">수단</th>
                        <th className="p-2 border">날짜</th>
                      </tr>
                    </thead>
                    <tbody>
                      <tr>
                        <td className="p-2 border">P20240601-001</td>
                        <td className="p-2 border">50,000원</td>
                        <td className="p-2 border">카드</td>
                        <td className="p-2 border">2024-06-01</td>
                      </tr>
                    </tbody>
                  </table>
                </div>
              )}
              {activeTab === 'favorits' && (
                <div>
                  <div className="font-bold mb-2">즐겨찾기한 서비스</div>
                  <ul className="text-sm text-gray-700">
                    <li>인스타그램 팔로워 500명</li>
                    <li>유튜브 구독자 100명</li>
                  </ul>
                </div>
              )}
              {activeTab === 'settings' && (
                <div>
                  <div className="font-bold mb-2">환경설정</div>
                  <div className="text-sm text-gray-700">알림 설정, 비밀번호 변경 등 환경설정 기능이 여기에 표시됩니다.</div>
                </div>
              )}
            </div>
          )}
        </section>
      </div>
    </div>
  );
};

export default UserPage;
